INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, 1, "調子が上がって\nきたなっ", 2, "訓練はまだ\nここからですわ", "vo_minigame_1013_icon_1_002_001", 1000, "vo_minigame_1013_icon_2_002_001", 3000, 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, 2, "ほらほら、\nまだいけるだろ？", 2, "クスクス、悪くない\n流れですわね", "vo_minigame_1013_icon_1_003_001", 5000, "vo_minigame_1013_icon_2_003_001", 3000, 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 3, "へへっ、おまえら\nやるじゃねえか！", 2, "すばらしい\n記録ですわ", "vo_minigame_1013_icon_1_004_001", 10000, "vo_minigame_1013_icon_2_004_001", 3000, 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 4, "あたしたちはまだ\n止まらねえぜ！", 3, "乗りに乗って\nいますわね", "vo_minigame_1013_icon_1_005_001", 10000, "vo_minigame_1013_icon_2_005_001", 3000, 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 5, "見てろよ！\nマコト班の快進撃だ！", 3, "まだまだ行きます\nついてきなさい", "vo_minigame_1013_icon_1_005_002", 10000, "vo_minigame_1013_icon_2_005_002", 3000, 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 6, "うおぉぉっ！\n絶好調だぜ！", 3, "エリコ班の\n本領発揮ですわ！", "vo_minigame_1013_icon_1_005_003", 10000, "vo_minigame_1013_icon_2_005_003", 3000, 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 7, "どこまで行けるか\n楽しみだなっ！", 4, "ここからは\n前人未到の領域です！", "vo_minigame_1013_icon_1_006_001", 0, "vo_minigame_1013_icon_2_006_001", 3000, 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (4, 8, "まだ諦めんなよっ", 5, "厄介でしたわ…", "vo_minigame_1013_icon_1_007_001", 1, "vo_minigame_1013_icon_2_007_001", 1000, 3);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (4, 9, "冷やっとしたぜ…！", 5, "油断大敵です", "vo_minigame_1013_icon_1_007_002", 1, "vo_minigame_1013_icon_2_007_002", 1000, 3);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (4, 10, "弱音を吐くなっ", 5, "忌々しいっ…", "vo_minigame_1013_icon_1_007_003", 1, "vo_minigame_1013_icon_2_007_003", 1000, 3);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 11, "マコト班集合！", 6, "大所帯ですわね", "vo_minigame_1013_icon_1_008_001", 99, "vo_minigame_1013_icon_2_008_001", 1500, 4);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 12, "連携してくぞ！", 6, "エリコ班へようこそ", "vo_minigame_1013_icon_1_008_002", 99, "vo_minigame_1013_icon_2_008_002", 1500, 4);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (6, 13, "みんなに力を！", 8, "ナナカちゃんに\nお任せあれ", "vo_minigame_1013_icon_1_020_001", 0, "vo_minigame_1013_icon_2_020_001", 3000, 1);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (7, 14, "任せてくれたまえ", 9, "はっはっは！\n任せろ！", "vo_minigame_1013_icon_1_022_001", 0, "vo_minigame_1013_icon_2_022_001", 3000, 1);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (8, 15, "ほな、いきまひょか", 10, "どんどんいくわよ", "vo_minigame_1013_icon_1_023_001", 0, "vo_minigame_1013_icon_2_023_001", 3000, 1);
